div.script:
(function () {
    document.addEventListener('DOMContentLoaded', function () {
        const btn     = document.getElementById('kuale-privacy-btn');
        const overlay = document.getElementById('kuale-privacy-overlay');
        const close   = document.getElementById('kuale-privacy-close');

        function getBlurTargets() {
            return Array.from(document.querySelectorAll('#wrapwrap > *'))
                .filter(el => !el.contains(overlay) && el.id !== 'footer');
        }

        function openModal() {
            overlay.classList.add('is-open');
            document.body.classList.add('modal-open');
            getBlurTargets().forEach(el => el.classList.add('kuale-blur-bg'));
            document.querySelectorAll('.kuale-footer__wrap, .kuale-footer__bottom')
                .forEach(el => el.classList.add('kuale-blur-bg'));
        }
        window.kualeOpenPrivacyModal = openModal;

        function closeModal() {
            overlay.classList.remove('is-open');
            document.body.classList.remove('modal-open');
            document.querySelectorAll('.kuale-blur-bg')
                .forEach(el => el.classList.remove('kuale-blur-bg'));
        }
        window.kualeClosePrivacyModal = closeModal;

        if (btn) btn.addEventListener('click', function (e) { e.preventDefault(); openModal(); });
        if (close) close.addEventListener('click', closeModal);
        if (overlay) overlay.addEventListener('click', function (e) { if (e.target === overlay) closeModal(); });
        document.addEventListener('keydown', function (e) { if (e.key === 'Escape') closeModal(); });
    });
})();
